import React, { useEffect, useState } from 'react';
import { Link, useParams } from 'react-router-dom';
import toast from 'react-hot-toast';
import ChatBox from '../components/chat/ChatBox';
import { nguoiDungAPI } from '../services/api';
import useAuthStore from '../store/authStore';
import './TrangCaNhanCongKhai.css';

const formatJoinDate = value => (
  value ? new Date(value).toLocaleDateString('vi-VN') : 'Chua cap nhat'
);

export default function TrangCaNhanCongKhai() {
  const { id } = useParams();
  const { user } = useAuthStore();
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    setLoading(true);
    nguoiDungAPI.layTrangCaNhanCongKhai(id)
      .then(response => setProfile(response.data.data))
      .catch(error => {
        setProfile(null);
        toast.error(error.response?.data?.message || 'Khong tai duoc ho so cong khai');
      })
      .finally(() => setLoading(false));
  }, [id]);

  if (loading) {
    return <div className="spinner" />;
  }

  if (!profile) {
    return (
      <div className="container page-wrapper">
        <div className="alert alert-danger">Khong tim thay ho so cong khai nay.</div>
      </div>
    );
  }

  const isOwnProfile = user?.maNguoiDung === profile.maNguoiDung;
  const avatar = profile.avatar
    || `https://ui-avatars.com/api/?name=${encodeURIComponent(profile.hoTen || 'U')}&background=12355B&color=fff&size=160`;

  return (
    <div className="container page-wrapper">
      <div className="public-profile-layout">
        <div>
          <div className="card public-profile-hero">
            <div className="card-body public-profile-hero-body">
              <div className="public-profile-avatar">
                <img src={avatar} className="avatar avatar-xl public-profile-avatar-image" alt={profile.hoTen} />
              </div>

              <div className="public-profile-main">
                <div className="public-profile-title-row">
                  <h1>{profile.hoTen}</h1>
                  {profile.xacThuc && <span className="badge badge-success">Da xac thuc</span>}
                </div>

                <p className="public-profile-subtitle">
                  Ho so cong khai nay tong hop danh gia, so phong da quan ly va cac thong tin de ban de dang ket noi.
                </p>

                <div className="public-profile-meta">
                  <span>Tham gia tu: {formatJoinDate(profile.ngayTao)}</span>
                  <span>Diem danh gia: {profile.diemDanhGia ? profile.diemDanhGia.toFixed(1) : 'Chua co'}</span>
                  <span>Bai dang: {profile.tongBaiDang || 0}</span>
                  <span>Phong dang quan ly: {profile.tongPhong || 0}</span>
                </div>

                <div className="public-profile-actions">
                  {isOwnProfile ? (
                    <Link to="/ho-so" className="btn btn-primary">Ve ho so cua toi</Link>
                  ) : (
                    <a href="#chat-frame" className="btn btn-primary">Nhan tin ngay</a>
                  )}
                </div>
              </div>
            </div>
          </div>

          <div className="public-profile-stats">
            <div className="public-profile-stats-grid">
              <div className="stat-card">
                <div className="stat-value">{profile.tongPhong || 0}</div>
                <div className="stat-label">Phong dang quan ly</div>
              </div>
              <div className="stat-card">
                <div className="stat-value">{profile.tongBaiDang || 0}</div>
                <div className="stat-label">Bai dang da tao</div>
              </div>
              <div className="stat-card">
                <div className="stat-value">{profile.diemDanhGia ? profile.diemDanhGia.toFixed(1) : '0.0'}</div>
                <div className="stat-label">Diem uy tin</div>
              </div>
            </div>
          </div>

          <div className="card">
            <div className="card-header">Danh gia nhan duoc</div>
            <div className="card-body">
              {!profile.danhGiaNhanDuoc?.length ? (
                <div className="review-empty">Nguoi dung nay chua co danh gia cong khai nao.</div>
              ) : (
                <div className="review-list">
                  {profile.danhGiaNhanDuoc.map(review => (
                    <div key={review.maDanhGia} className="review-item">
                      <Link to={`/nguoi-dung/${review.maNguoiDanhGia}`} className="public-profile-reviewer">
                        <img
                          src={review.avatarNguoiDanhGia || `https://ui-avatars.com/api/?name=${encodeURIComponent(review.tenNguoiDanhGia || 'U')}&background=12355B&color=fff&size=48`}
                          className="avatar avatar-sm"
                          alt={review.tenNguoiDanhGia}
                        />
                        <div>
                          <strong>{review.tenNguoiDanhGia || 'Nguoi dung an danh'}</strong>
                          <div className="message-time">
                            {review.ngayDanhGia ? new Date(review.ngayDanhGia).toLocaleDateString('vi-VN') : ''}
                          </div>
                        </div>
                      </Link>
                      <div className="stars">{'★'.repeat(review.soSao)}{'☆'.repeat(5 - review.soSao)}</div>
                      <div className="public-profile-review-content">
                        {review.moTa || 'Khong co nhan xet chi tiet'}
                      </div>
                    </div>
                  ))}
                </div>
              )}
            </div>
          </div>
        </div>

        <div className="public-profile-sidebar">
          <div className="card public-profile-frame">
            <div className="card-header">Frame ket noi</div>
            <div className="card-body">
              {isOwnProfile ? (
                <div className="public-profile-owner-note">
                  Day la che do xem cong khai cua chinh ban. Cac nguoi dung khac se thay frame lien he va khung chat tai day.
                </div>
              ) : user ? (
                <div className="public-profile-owner-note">
                  Ban dang xem ho so cong khai cua {profile.hoTen}. Co the nhan tin truc tiep realtime o khung ben duoi.
                </div>
              ) : (
                <>
                  <div className="public-profile-owner-note">
                    Dang nhap de nhan tin realtime voi nguoi dung nay.
                  </div>
                  <Link to="/dang-nhap" className="btn btn-primary btn-block" style={{ marginTop: 16 }}>
                    Dang nhap de chat
                  </Link>
                </>
              )}
            </div>
          </div>

          {!isOwnProfile && user && (
            <div className="card public-profile-chat-card" id="chat-frame">
              <div className="card-header">Nhan tin realtime</div>
              <div className="card-body public-profile-chat-body">
                <ChatBox
                  maNguoiKia={profile.maNguoiDung}
                  tenNguoiKia={profile.hoTen}
                  avatarNguoiKia={profile.avatar}
                  embedded
                />
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
